// ── CLIENT ROSTER ──────────────────────────────────────────
// Add each active client here. SmartPM project IDs from your
// SmartPM account dashboard under Settings > Projects.

const clients = [
  {
    name: 'TDI — Transmission Developers Inc',
    project_id: 'SMARTPM_PROJECT_ID_TDI',
    contact: 'Scott',
    report_type: 'Owner Advisory',
    contract_value: 'Retainer'
  },
  // Add additional clients here as you onboard them:
  // { name: 'Client 2', project_id: 'SMARTPM_PROJECT_ID_2', ... }
];

const month = new Date().toLocaleString('default', { month: 'long' });
const year = new Date().getFullYear();

return clients.map(c => ({ json: { ...c, report_month: month, report_year: year, report_period: `${month} ${year}` } }));
